pandoc 
  to: latex
  output-file: report.tex
  standalone: true
  pdf-engine: xelatex
  variables:
    graphics: true
    tables: true
  default-image-extension: pdf
  toc: false
  number-sections: true

metadata
  block-headings: true
  title: ''
  subtitle: ''
  author: ''
  date: ''
  documentclass: article
  lof: false
  lot: false
  colorlinks: false
  lang: es
  mainfont: Times New Roman
  fontsize: 11pt
  linestretch: 1.5
  geometry:
    - top=2.5cm
    - bottom=2.5cm
    - left=2.5cm
    - right=2.5cm
  header-includes:
    - \usepackage{fancyhdr}
    - \usepackage{float}
    - \usepackage{graphicx}
    - \usepackage{lastpage}
    - \usepackage{titlesec}
    - \usepackage{pdflscape}
    - \usepackage{caption}
    - \usepackage{subcaption}
    - \usepackage{tocloft}
    - \usepackage{setspace}
    - \usepackage{indentfirst}
    - \setlength{\parindent}{1.25cm}
    - \setlength{\parskip}{6pt}
    - \renewcommand{\figurename}{Figura}
    - \renewcommand{\tablename}{Tabla}
    - \renewcommand{\cftfigpresnum}{\textbf{Figura }\textbf}
    - \renewcommand{\cftfigaftersnum}{.\ }
    - \setlength{\cftfignumwidth}{1.5cm}
    - \renewcommand{\cfttabpresnum}{\textbf{Tabla }\textbf}
    - \renewcommand{\cfttabaftersnum}{.\ }
    - \setlength{\cfttabnumwidth}{1.5cm}
    - \renewcommand{\cftsecfont}{\bfseries}
    - \renewcommand{\cftsecpagefont}{\bfseries}
    - \captionsetup[figure]{labelfont=bf, font=small}
    - \captionsetup[table]{labelfont=bf, font=small}
    - \makeatletter
    - \let\ps@plain\ps@fancy
    - \makeatother
    - \pagestyle{fancy}
    - \fancyhf{}
    - \fancyhead[L]{\includegraphics[height=1cm]{../assets/logo.png}}
    - \fancyhead[C]{\textbf{Parque Solar Alpha}\\ \small Informe de Gestión de Fauna}
    - \fancyhead[R]{}
    - \fancyfoot[C]{\thepage}
    - \renewcommand{\headrulewidth}{0.4pt}
    - \renewcommand{\footrulewidth}{0pt}

